#!/usr/bin/env python3
"""
VETx Logo Patcher
รันสคริปต์นี้ในโฟลเดอร์เดียวกับไฟล์ HTML ของคุณ:
  python3 patch_logo.py
"""
import sys

INPUT_FILE = "index.html"   # ← เปลี่ยนชื่อไฟล์ถ้าจำเป็น
OUTPUT_FILE = "index.html"

with open(INPUT_FILE, 'r', encoding='utf-8') as f:
    html = f.read()

patches = [
    (
        '    <title>VETx | Vet Clinical Simulation</title>',
        '    <title>VETx | Vet Clinical Simulation</title>\n    <link rel="icon" type="image/png" href="data:image/png;base64,">\n    <link rel="apple-touch-icon" href="data:image/png;base64,">',
        "Favicon in <head>"
    ),
    (
        '        <div class="flex items-center gap-2">\n            <div class="bg-teal-600 p-1.5 rounded-lg text-white shadow-sm relative">\n                <i data-lucide="stethoscope" class="w-4 h-4"></i>\n                <div id="ai-status-dot" class="absolute -top-1 -right-1 w-2.5 h-2.5 bg-gray-300 rounded-full border-2 border-white"></div>\n            </div>\n            <h1 class="font-heading font-bold text-lg text-slate-800 tracking-tight">VET<span class="text-teal-600">x</span> <span class="text-[10px] text-slate-400 font-normal border border-slate-200 rounded px-1 ml-1 bg-slate-50">AI-Diag</span></h1>\n        </div>',
        '        <div class="flex items-center gap-2">\n            <div class="relative">\n                <img src="data:image/png;base64," alt="VETx Logo" class="w-9 h-9 object-contain">\n                <div id="ai-status-dot" class="absolute -top-0.5 -right-0.5 w-2.5 h-2.5 bg-gray-300 rounded-full border-2 border-white"></div>\n            </div>\n            <h1 class="font-heading font-bold text-lg text-slate-800 tracking-tight">VET<span class="text-teal-600">x</span> <span class="text-[10px] text-slate-400 font-normal border border-slate-200 rounded px-1 ml-1 bg-slate-50">AI-Diag</span></h1>\n        </div>',
        "Header Logo"
    ),
    (
        '            <div class="w-20 h-20 bg-teal-100 rounded-full flex items-center justify-center mx-auto mb-6 text-teal-600"><i data-lucide="user-plus" class="w-10 h-10"></i></div>',
        '            <div class="w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6 overflow-hidden bg-slate-50 border-2 border-teal-100"><img src="data:image/png;base64," alt="VETx" class="w-14 h-14 object-contain"></div>',
        "Register Modal Icon"
    ),
]

for old, new, label in patches:
    if old in html:
        html = html.replace(old, new, 1)
        print(f"✅ Applied: {label}")
    else:
        print(f"⚠️  Not found (อาจถูก patch ไปแล้ว): {label}")

with open(OUTPUT_FILE, 'w', encoding='utf-8') as f:
    f.write(html)

print(f"\n🎉 Done! ไฟล์ถูกบันทึกที่ {OUTPUT_FILE}")
